import{_ as i,c as r,o as t,ag as a}from"./chunks/framework.Dj4VfQLU.js";const g=JSON.parse('{"title":"Driver App Workflows","description":"","frontmatter":{"icon":"car-side"},"headers":[],"relativePath":"driver-app-workflows.md","filePath":"driver-app-workflows.md"}'),l={name:"driver-app-workflows.md"};function o(n,e,s,p,d,c){return t(),r("div",null,e[0]||(e[0]=[a('<h1 id="driver-app-workflows" tabindex="-1">Driver App Workflows <a class="header-anchor" href="#driver-app-workflows" aria-label="Permalink to &quot;Driver App Workflows&quot;">​</a></h1><p>The <strong>BetterTaxi Driver App</strong> (located at <code>apps/taxi-driver-frontend/</code>) is a professionally structured Flutter app tailored for service providers like ride-hailing drivers, couriers, and delivery partners. It gives them access to job offers, trip tracking, earnings visibility, and customer communication — all in real time.</p><p>This app is fully modular and supports multi-service operations such as <strong>rides</strong>, <strong>parcel delivery</strong>, and <strong>multi-stop/multi-shop</strong> trips.</p><hr><h4 id="🧭-general-workflow-overview" tabindex="-1">🧭 General Workflow Overview <a class="header-anchor" href="#🧭-general-workflow-overview" aria-label="Permalink to &quot;🧭 General Workflow Overview&quot;">​</a></h4><ol><li>Driver registers and uploads documents</li><li>Admin verifies the account and assigns service access</li><li>Driver goes online and accepts jobs</li><li>Completes trip using navigation of choice</li><li>Views earnings and history in real time</li></ol><hr><h4 id="🪪-1-registration-verification" tabindex="-1">🪪 1. Registration &amp; Verification <a class="header-anchor" href="#🪪-1-registration-verification" aria-label="Permalink to &quot;🪪 1. Registration &amp; Verification&quot;">​</a></h4><ul><li>Drivers can <strong>self-register directly through the app</strong></li><li>Required documents (e.g., ID, license, vehicle insurance) are defined per region by the admin</li><li>Drivers cannot proceed to use the app until approved</li></ul><p><strong>✅ Document Rules</strong></p><ul><li>Admins define document types and requirements per region</li><li>Expiration logic is built-in: <ul><li>Expired documents <strong>disable the driver</strong> from operating until updated</li><li>The system prompts re-submission upon login</li></ul></li></ul><hr><h4 id="🟢-2-availability-management" tabindex="-1">🟢 2. Availability Management <a class="header-anchor" href="#🟢-2-availability-management" aria-label="Permalink to &quot;🟢 2. Availability Management&quot;">​</a></h4><ul><li>Once verified, drivers can <strong>toggle their availability</strong> status: <ul><li><strong>Online</strong>: begins location tracking and activates dispatch subscription</li><li><strong>Offline</strong>: stops receiving trip requests and halts live updates</li></ul></li></ul><p><strong>🔌 Service Activation</strong></p><ul><li>Admins control which services (e.g., parcel delivery, ride-share) each driver has access to</li><li>Drivers can activate/deactivate available services individually</li></ul><blockquote><p>🔄 Auto-offline (e.g., due to battery saving or idling) is <strong>not yet supported</strong></p></blockquote><hr><h4 id="📲-3-trip-offers-acceptance" tabindex="-1">📲 3. Trip Offers &amp; Acceptance <a class="header-anchor" href="#📲-3-trip-offers-acceptance" aria-label="Permalink to &quot;📲 3. Trip Offers &amp; Acceptance&quot;">​</a></h4><ul><li>Dispatch follows a <strong>Broadcast Model</strong></li><li>Incoming offers include: <ul><li>Trip type (color-coded by category)</li><li>Estimated fare, distance, and pickup/drop-off details</li><li>Expected wait and ride time</li></ul></li><li>Drivers can: <ul><li><strong>Accept</strong> the offer</li><li><strong>Ignore</strong> it (request passes to next available driver)</li><li>View <strong>missed offers</strong> later for review</li></ul></li></ul><hr><h4 id="🧭-4-trip-execution-navigation" tabindex="-1">🧭 4. Trip Execution &amp; Navigation <a class="header-anchor" href="#🧭-4-trip-execution-navigation" aria-label="Permalink to &quot;🧭 4. Trip Execution &amp; Navigation&quot;">​</a></h4><ul><li>Once accepted, the trip progresses in stages: <ol><li>Navigate to pickup</li><li>Mark “Arrived”</li><li>Start trip (optional: OTP verification if enabled)</li><li>Navigate to drop-off</li><li>Mark “Completed”</li></ol></li></ul><p><strong>🚗 Route Choice</strong></p><ul><li>App displays a recommended best route</li><li>Drivers can override and use <strong>one of 11 supported external map apps</strong> (e.g., Google Maps, Waze, Apple Maps)</li></ul><p><strong>🚚 Multi-Stop &amp; Multi-Shop Trips</strong></p><ul><li>Supported for both ride and delivery types</li><li>Delivery orders are <strong>color-coded</strong> by category for fast visual recognition</li></ul><hr><h4 id="🔁-trip-cancellation" tabindex="-1">🔁 Trip Cancellation <a class="header-anchor" href="#🔁-trip-cancellation" aria-label="Permalink to &quot;🔁 Trip Cancellation&quot;">​</a></h4><ul><li>Drivers may <strong>cancel a trip after acceptance</strong></li><li>A cancellation reason is required and recorded</li><li>Cancelation fees (if applicable) are applied based on admin pricing rules</li></ul><hr><h4 id="💸-5-earnings-wallet" tabindex="-1">💸 5. Earnings &amp; Wallet <a class="header-anchor" href="#💸-5-earnings-wallet" aria-label="Permalink to &quot;💸 5. Earnings &amp; Wallet&quot;">​</a></h4><ul><li>Driver wallet is visible in-app and <strong>updates in real time</strong></li><li>Shows: <ul><li>Completed trip payments</li><li>Commissions and bonuses</li><li>Cancellations and adjustments</li></ul></li></ul><p><strong>💰 Payouts</strong></p><ul><li>Drivers <strong>cannot withdraw manually</strong></li><li>Admins process payouts: <ul><li>Automatically via Stripe Connect</li><li>Or by exporting payouts via CSV for manual processing</li></ul></li></ul><hr><h4 id="💬-6-communication-support" tabindex="-1">💬 6. Communication &amp; Support <a class="header-anchor" href="#💬-6-communication-support" aria-label="Permalink to &quot;💬 6. Communication &amp; Support&quot;">​</a></h4><p><strong>Chat</strong></p><ul><li>In-app chat is active <strong>during live trips only</strong></li><li>Optionally backed by SMS as a fallback</li></ul><p><strong>Announcements</strong></p><ul><li>Drivers receive persistent updates via the <strong>Announcements Tab</strong><ul><li>E.g., zone outages, policy changes, holiday schedules</li></ul></li></ul><hr><h4 id="🛠-7-settings-preferences" tabindex="-1">🛠 7. Settings &amp; Preferences <a class="header-anchor" href="#🛠-7-settings-preferences" aria-label="Permalink to &quot;🛠 7. Settings &amp; Preferences&quot;">​</a></h4><ul><li>Drivers can: <ul><li>Change <strong>light/dark mode</strong></li><li>Set and save preferred <strong>language</strong></li></ul></li><li><strong>App theming (colors)</strong> is not customizable by drivers (managed by platform)</li></ul><hr><h4 id="🧾-8-trip-history-ratings" tabindex="-1">🧾 8. Trip History &amp; Ratings <a class="header-anchor" href="#🧾-8-trip-history-ratings" aria-label="Permalink to &quot;🧾 8. Trip History &amp; Ratings&quot;">​</a></h4><ul><li>Drivers can: <ul><li>View past trips and fares</li><li>Rate customers after every trip (if enabled)</li></ul></li><li>Trip logs include timestamps, maps, fare details, and cancellation info (if applicable)</li></ul><hr><h4 id="📝-summary-workflow" tabindex="-1">📝 Summary Workflow <a class="header-anchor" href="#📝-summary-workflow" aria-label="Permalink to &quot;📝 Summary Workflow&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Step</th><th>Description</th></tr></thead><tbody><tr><td>Register &amp; Upload Docs</td><td>Regional requirements defined by admin</td></tr><tr><td>Await Admin Approval</td><td>Mandatory before receiving offers</td></tr><tr><td>Set Online &amp; Choose Services</td><td>Manually toggle availability and service types</td></tr><tr><td>Receive &amp; Accept Offers</td><td>Color-coded by type, broadcast-dispatched</td></tr><tr><td>Use In-App or External Navigation</td><td>11 supported map apps, or follow app&#39;s route</td></tr><tr><td>Complete or Cancel Trips</td><td>Multistep supported; cancellations require reasons</td></tr><tr><td>View Wallet &amp; Earnings</td><td>Updated in real time</td></tr><tr><td>Chat During Trips</td><td>With fallback to SMS if configured</td></tr><tr><td>See Announcements</td><td>Via dedicated in-app tab</td></tr></tbody></table>',50)]))}const h=i(l,[["render",o]]);export{g as __pageData,h as default};
